def f72(s, a):
    target_cx = s[9] + s[17] / 2.0
    target_cy = s[10] + s[18] / 2.0
    robot_x = s[0]
    dx = a[0]
    return ((robot_x < target_cx) and (dx > 0)) or ((robot_x > target_cx) and (dx < 0))

def f75(s, a):
    dx = a[0]
    dy = a[1]
    return abs(dx) > abs(dy)

def f76(s, a):
    dx = a[0]
    dy = a[1]
    return abs(dy) > abs(dx)
